1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type Step = { op: "quote"; items: Item[] };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
17	
18	const quotePremium = (items: Item[]): number => {
19	  const policyBase = items.reduce((sum, item) => sum + basePremium(item), 0);
20	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
21	  return Math.ceil(policyBase + firstInsuranceSurcharge) + PROCESSING_FEE;
22	};
23	
24	export const runScenario = (input: unknown): unknown => {
25	  const scenario = input as Scenario;
26	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
27	  return { results };
28	};
